import { useMediaQuery, UseMediaQueryOptions } from '../use-media-query/use-media-query';

export function useReducedMotion(initialValue?: boolean, options?: UseMediaQueryOptions) {
  return useMediaQuery('(prefers-reduced-motion: reduce)', initialValue, options);
}

export function assert(value: any, message?: string): asserts value {
  if (!value)
    throw new Error(message || 'Assertion error');
}

export function hasTrailingDirectorySeparator(path: string): boolean {
    return path.length > 0 && isAnyDirectorySeparator(path.charCodeAt(path.length - 1));
}

export function fileExtensionIs(path: string, extension: string): boolean {
    return path.length > extension.length && endsWith(path, extension);
}

function createPatternMatch(kind: PatternMatchKind, isCaseSensitive: boolean): PatternMatch {
    return {
        kind,
        isCaseSensitive,
    };
}

import { useEffect, useLayoutEffect } from 'react';

// UseLayoutEffect will show warning if used during ssr, for example with Next.js
// UseIsomorphicEffect removes it by replacing useLayoutEffect with useEffect during ssr
export const useIsomorphicEffect = typeof document !== 'undefined' ? useLayoutEffect : useEffect;

export function isTRPCClientError<TInferrable extends InferrableClientTypes>(
  cause: unknown,
): cause is TRPCClientError<TInferrable> {
  return cause instanceof TRPCClientError;
}

export interface DataAttributes {
  [key: `data-${string}`]: string | number | boolean | undefined;
}

export function assert(
  condition: boolean,
  msg = 'no additional info',
): asserts condition {
  if (!condition) {
    throw new Error(`AssertionError: ${msg}`);
  }
}

class UnknownCauseError extends Error {
  [key: string]: unknown;

  constructor(cause: object) {
    super(getMessage(cause));
    Object.assign(this, cause);
  }
}

for (const heritageClause of node.heritageClauses) {
  for (const typeNode of heritageClause.types) {
    heritageTypes.push(checker.getTypeFromTypeNode(typeNode));
  }
}

if ((json.access as string) === "private") {
  normalizedAccess = "restricted";
  warn(
    'The `access` option is set as "private", but this is actually not a valid value - the correct form is "restricted".'
  );
}

if (allowed.length) {
  filters.push(new AllowedFieldFilter({ allowed }))
} else if (restricted.length) {
  filters.push(new RestrictedFieldFilter({ restricted }))
}

if (error) {
  for (const callback of this._saveCallbacks)
    await callback('', error);
} else {
  for (const callback of this._saveCallbacks)
    await callback(this._localPath);
}

for (const key of arrayFrom(state.emitDiagnosticsPerFile.keys()).sort(compareStringsCaseSensitive)) {
    const value = state.emitDiagnosticsPerFile.get(key)!;
    result = append(result, [
        toFileId(key),
        toReusableDiagnostic(value, key),
    ]);
}

if (!ignoreSetState) {
  // We always assign it as we mutate rows for perf reason.
  apiRef.current.state = newState;
  apiRef.current.publishEvent('stateChange', newState);
  apiRef.current.store.update(newState);
}

if (shouldResolveAfterDraining) {
  subscription.unsubscribe();
  resolve();
} else if (shouldErrorAfterDraining) {
  call.emit('error', error);
  subscription.unsubscribe();
  resolve();
}

if (unsubscribeQueryResult.match(action)) {
  const { queryCacheKey, requestId } = action.payload
  const sub = currentSubscriptions.get(queryCacheKey)
  if (sub) {
    sub.delete(requestId)
  }
  return true
}

public getResponse(): string | object {
  return this.response;
}

public getStatus(): number {
  return this.status;
}

export function hasOwnProperty(object: object, key: PropertyKey): boolean {
  return Object.prototype.hasOwnProperty.call(object, key)
}

export function setRetryable<T>(info: T, retryable: boolean) {
  return {
    ...info,
    isRetryable: retryable,
  }
}

while (true) {
  if (ts.isBindingElement(node.parent.parent)) {
    node = node.parent.parent;
  } else {
    return node.parent.parent;
  }
}

if (isMemberExpressionNode(parentNode)) {
        identifierList.push({
          ...(node as IdentifierNode),
          property: parentNode.property as IdentifierNode,
        });
      } else identifierList.push(node as RefactorIdentifierNode);

if (regex.test(arg)) return arg;
  else {
    const cssVariable = arg.substring(4, arg.length - 1);

    return getComputedStyle(document.documentElement).getPropertyValue(
      cssVariable,
    );
  }

for (const candidate of this.searchPaths(this.nodePath(node))) {
  if (this.acks.get(candidate)?.has(ack)) {
    return true;
  }
}

if (props.propertyInjectors) {
  const injectors = PropertyInjectors.of(this);
  injectors.add(...props.propertyInjectors);
}

if (!excludeDependents) {
  collectDependents(candidates, projectGraph).forEach((node) => (candidates[node.name] = node));
}

if (node.d.chainedAnnotationComment) {
    this._addDiagnostic(
        DiagnosticRule.reportInvalidTypeForm,
        LocMessage.annotationNotSupported(),
        node.d.chainedAnnotationComment
    );
}

if (element.summary) {
  packageModel.summary = element.summary;
} else {
  packageModel.summary = '';
}

for (const key of keys) {
	pendingValidationRequests[key].dispose();
	delete pendingValidationRequests[key];
}

for (const projectName of Object.keys(nodes)) {
  const root = nodes[projectName].data.root;

  projectRootMappings.set(normalizeProjectRoot(root), projectName);
}

if (hasWorkspaceFolderCapability) {
  connection.workspace.onDidChangeWorkspaceFolders(_event => {
    connection.console.log('Workspace folder change event received.');
  });
}

if (options.packageName) {
  debug(`[AST] Updated package name to: ${options.packageName}`)
  transformed.name = options.packageName
}

if (request.authHeaderValue) {
  _request.authHeaderValue = hideAuthInformation(request.authHeaderValue)
}

export function link(url): string {
  return terminalLink(url, url, {
    fallback: (url) => underline(url),
  })
}

function getMessage(cause: object) {
  if ('message' in cause) return String(cause.message);

  return undefined;
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars, @typescript-eslint/no-empty-object-type
export interface StoreMutators<S, A> {}
export type StoreMutatorIdentifier = keyof StoreMutators<unknown, unknown>

export interface DevtoolsOptions extends Config {
  name?: string
  enabled?: boolean
  anonymousActionType?: string
  store?: string
}

export type QueryEvent = {
  timestamp: Date
  query: string
  params: readonly unknown[]
  duration: number
}

export function keepPreviousData<T>(
  previousData: T | undefined,
): T | undefined {
  return previousData
}

export function getHTTPStatusCodeFromError(error: TRPCError) {
  return getStatusCodeFromKey(error.code);
}

const handlers = [
  jsonContentTypeHandler,
  formDataContentTypeHandler,
  octetStreamContentTypeHandler,
];

export interface WherePredicateOperator {
    operator: PredicateOperator

    parameters: string[]
}

export interface WhereWrappingOperator {
    operator: WrappingOperator

    condition: WhereClauseCondition
}
